import { describe, expect, it } from 'vitest';
import { createClockAtlas } from './clock-atlas';
import type { ClockAtlasPacket } from './clock-atlas';
import { createDistributedClockMesh } from './clock-distributed';
import type { ProcessClock } from './clock-distributed';

// ─── Fixtures ───────────────────────────────────────────────────────

const sfClock: ProcessClock = {
  id: 'pid:sf',
  label: 'SF Edge',
  location: { lat: 37.62, lon: -122.38, region: 'SFO' },
  phase: 'active',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now(),
  requestRate: 150,
};

const tokyoClock: ProcessClock = {
  id: 'pid:tokyo',
  label: 'Tokyo Edge',
  location: { lat: 35.76, lon: 140.39, region: 'NRT' },
  phase: 'active',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now(),
  requestRate: 200,
};

const londonClock: ProcessClock = {
  id: 'pid:london',
  label: 'London Edge',
  location: { lat: 51.47, lon: -0.46, region: 'LHR' },
  phase: 'idle',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now() - 5000,
  requestRate: 0,
};

function buildMesh(toleranceMs?: number) {
  return createDistributedClockMesh([sfClock, tokyoClock, londonClock], toleranceMs);
}

// ─── createClockAtlas ───────────────────────────────────────────────

describe('createClockAtlas', () => {
  it('produces correct source identifier', () => {
    const atlas = createClockAtlas(buildMesh());
    expect(atlas.source).toBe('GnosisClockAtlas');
  });

  it('body count matches clock count', () => {
    const mesh = buildMesh();
    const atlas = createClockAtlas(mesh);
    expect(atlas.bodies.length).toBe(mesh.clocks.length);
  });

  it('edge count matches mesh edge count', () => {
    const mesh = buildMesh();
    const atlas = createClockAtlas(mesh);
    expect(atlas.edges.length).toBe(mesh.edges.length);
  });

  it('bodies have lat/lon from colo lookup', () => {
    const atlas = createClockAtlas(buildMesh());
    const sfBody = atlas.bodies.find(b => b.id === 'pid:sf');
    expect(sfBody).toBeDefined();
    expect(sfBody!.lat).toBeCloseTo(37.62, 1);
    expect(sfBody!.lon).toBeCloseTo(-122.38, 1);
    expect(sfBody!.city).toBe('San Francisco');
  });

  it('bodies have correct phase mapping', () => {
    const atlas = createClockAtlas(buildMesh());
    const sfBody = atlas.bodies.find(b => b.id === 'pid:sf');
    const londonBody = atlas.bodies.find(b => b.id === 'pid:london');
    expect(sfBody!.phase).toBe('active');
    expect(londonBody!.phase).toBe('idle');
  });

  it('litFraction matches mesh litFraction', () => {
    const mesh = buildMesh();
    const atlas = createClockAtlas(mesh);
    expect(atlas.litFraction).toBe(mesh.litFraction);
  });

  it('networkDiameterMs matches mesh networkDiameterMs', () => {
    const mesh = buildMesh();
    const atlas = createClockAtlas(mesh);
    expect(atlas.networkDiameterMs).toBe(mesh.networkDiameterMs);
  });

  it('edges have PROCESS or VENT type', () => {
    const atlas = createClockAtlas(buildMesh());
    for (const edge of atlas.edges) {
      expect(['PROCESS', 'VENT']).toContain(edge.edgeType);
    }
  });

  it('activeCount and totalCount are correct', () => {
    const mesh = buildMesh();
    const atlas = createClockAtlas(mesh);
    expect(atlas.activeCount).toBe(2); // SF + Tokyo are active
    expect(atlas.totalCount).toBe(3);
  });
});
